function BoolToggle({ value, onChange }: { value: boolean; onChange: (v: boolean) => void }) {
  const [checked, setChecked] = useState(value)
  return (
    <label style={{ position: 'relative', display: 'inline-block', width: 32, height: 16, flexShrink: 0, cursor: 'pointer' }}>
      <input
        type="checkbox"
        checked={checked}
        onChange={e => {
          setChecked(e.target.checked)
          onChange(e.target.checked)
        }}
        style={{ opacity: 0, width: 0, height: 0, position: 'absolute' }}
      />
      <span style={{
        position: 'absolute', inset: 0,
        background: checked ? '#4caf50' : '#555',
        borderRadius: 16,
        transition: 'background 0.2s ease',
      }} />
      <span style={{
        position: 'absolute',
        top: 2, left: checked ? 18 : 2,
        width: 12, height: 12,
        background: '#fff',
        borderRadius: '50%',
        transition: 'left 0.2s ease',
        boxShadow: '0 1px 2px rgba(0,0,0,0.4)',
      }} />
    </label>
  )
}

// Round 635: Inspector Transform Ž≥Ķžā¨/Ž∂ôžó¨ŽĄ£Íłį ‚ÄĒ module-level fallback
type TransformSnapshot = {
  position: CCSceneNode['position']
  rotation: CCSceneNode['rotation']
  scale: CCSceneNode['scale']
  size: CCSceneNode['size']
  anchor: CCSceneNode['anchor']
  opacity: number
}
let transformClipboard: TransformSnapshot | null = null

// R1418: žĒ¨ žú†Ūö®žĄĪ Í≤Äžā¨ (Lint)
interface ValidationIssue {
  level: 'error' | 'warning'
  message: string
  nodeUuid?: string
  nodeName?: string
}

// R1441: žĶúž†ĀŪôĒ ž†úžēą žĚłŪĄįŪéėžĚīžä§ (cc-file-parseržôÄ ŽŹôÍłįŪôĒ)
interface OptimizationSuggestion {
  type: 'performance' | 'memory' | 'structure'
  severity: 'high' | 'medium' | 'low'
  message: string
  affectedUuids?: string[]
}

function validateScene(root: CCSceneNode): ValidationIssue[] {
  const issues: ValidationIssue[] = []
  const seenUuids = new Map<string, string>() // uuid ‚Üí name
  let hasCanvas = false

  function walk(node: CCSceneNode, depth: number, parentActive: boolean): void {
    // UUID ž§ĎŽ≥Ķ ž≤īŪĀ¨
    if (seenUuids.has(node.uuid)) {
      issues.push({ level: 'error', message: `UUID ž§ĎŽ≥Ķ: "${node.name}" žôÄ "${seenUuids.get(node.uuid)}" (${node.uuid.slice(0, 8)}...)`, nodeUuid: node.uuid, nodeName: node.name })
    } else {
      seenUuids.set(node.uuid, node.name)
    }

    // žĚīŽ¶Ą ŽĻą ŽÖłŽďú
    if (node.name === '') {
      issues.push({ level: 'warning', message: `žĚīŽ¶Ą ŽĻą ŽÖłŽďú (uuid: ${node.uuid.slice(0, 8)}...)`, nodeUuid: node.uuid, nodeName: '(empty)' })
    }

    // Canvas ÍįźžßÄ
    if (node.components.some(c => c.type === 'cc.Canvas')) hasCanvas = true

    // ŽĻĄŪôúžĄĪ Ž∂ÄŽ™® žēĄŽěė ŪôúžĄĪ žěźžčĚ
    if (!parentActive && node.active) {
      issues.push({ level: 'warning', message: `ŽĻĄŪôúžĄĪ Ž∂ÄŽ™® žēĄŽěė ŪôúžĄĪ žěźžčĚ: "${node.name}"`, nodeUuid: node.uuid, nodeName: node.name })
    }

    // ÍĻäžĚī Í≤ĹÍ≥†
    if (depth > 8) {
      issues.push({ level: 'warning', message: `Í≥ĄžłĶ ÍĻäžĚī ${depth}: "${node.name}" (8 žīąÍ≥ľ)`, nodeUuid: node.uuid, nodeName: node.name })
    }

    for (const child of node.children) {
      walk(child, depth + 1, node.active)
    }
  }

  walk(root, 0, true)

  // Canvas žóÜŽäĒ žĒ¨ Í≤ĹÍ≥† (Ž£®ŪäłÍįÄ ScenežĚł Í≤Ĺžöį)
  if (!hasCanvas && root.children.length > 0) {
    issues.push({ level: 'warning', message: 'Canvas žĽīŪŹ¨ŽĄĆŪäłÍįÄ žóÜŽäĒ žĒ¨ (CC 2.xžóźžĄú UIÍįÄ ŪĎúžčúŽźėžßÄ žēäžĚĄ žąė žěąžĚĆ)' })
  }

  return issues
}

