            {([[100,100],[200,100],[100,200],[200,200],[300,100]] as const).map(([w, h]) => (
              <span key={`${w}x${h}`} onClick={() => applyNodeSize(w, h)} title={`size=${w}√ó${h}`}
                style={{ fontSize: 8, cursor: 'pointer', padding: '1px 4px', borderRadius: 2, border: '1px solid var(--border)', color: '#94a3b8', userSelect: 'none' }}>{w}√ó{h}</span>
            ))}
